// ============================================================
//  LOCATION SECTION COMPONENT
//  – Contact info + embedded Google Map
//  – EDIT: address, phone, email, hours, map URL below
// ============================================================

import React from 'react';
import '../styles/Location.css';

// ── EDIT ALL CONTACT DETAILS HERE ────────────────────────────
const CONTACT = {
  address:   'Sandriyana Estate\nNegombo Road, Western Province\nSri Lanka',
  phone:     '+94 XX XXX XXXX',
  whatsapp:  '94XXXXXXXXX',        // no + sign
  email:     'info@sandrianaestate.com',
  website:   'sandrianaestate.com',
  hours:     'Mon – Sat: 8:00 AM – 6:00 PM\nSunday: 9:00 AM – 3:00 PM',
};

// ── EDIT: paste your Google Maps embed src URL here ──────────
// How to get it: Google Maps → search your location → Share → Embed a map → copy src="..."
const MAP_SRC =
  'https://maps.app.goo.gl/61Q6MACwE5SVw7KQA?g_st=iw';
// ─────────────────────────────────────────────────────────────

const items = [
  { icon: '📍', label: 'Address',            value: CONTACT.address,  link: null },
  { icon: '📞', label: 'Phone / WhatsApp',   value: CONTACT.phone,    link: `tel:${CONTACT.phone}` },
  { icon: '✉️', label: 'Email',              value: CONTACT.email,    link: `mailto:${CONTACT.email}` },
  { icon: '🕐', label: 'Opening Hours',      value: CONTACT.hours,    link: null },
  { icon: '🌐', label: 'Website',            value: CONTACT.website,  link: `https://${CONTACT.website}` },
];

export default function Location() {
  return (
    <section id="location" className="section-wrap location-section">

      {/* Header */}
      <div className="section-header">
        <div className="section-eyebrow">Find Us</div>
        <h2 className="section-title">Visit the <em>Estate</em></h2>
        <p style={{ color: 'var(--text-lt)', fontSize: '0.95rem', fontWeight: 300, lineHeight: 1.8 }}>
          Come experience the beauty of Sandriyana Estate in person.
          We welcome visitors by appointment.
        </p>
        <div className="divider" />
      </div>

      <div className="location-wrap">

        {/* ── LEFT: Contact info ── */}
        <div className="location-info">
          {items.map(({ icon, label, value, link }) => (
            <div key={label} className="contact-item">
              <div className="contact-icon">{icon}</div>
              <div className="contact-text">
                <strong>{label}</strong>
                {link
                  ? <a href={link} target={link.startsWith('http') ? '_blank' : undefined} rel="noreferrer">{value}</a>
                  : <span style={{ whiteSpace: 'pre-line' }}>{value}</span>
                }
              </div>
            </div>
          ))}

          {/* Action buttons */}
          <div className="location-actions">
            <a
              href={`https://wa.me/${CONTACT.whatsapp}`}
              target="_blank"
              rel="noreferrer"
              className="btn-primary"
            >
              💬 WhatsApp Us
            </a>
            <a
              href="https://maps.google.com/?q=Negombo+Sri+Lanka"
              target="_blank"
              rel="noreferrer"
              className="btn-outline-dark"
            >
              📍 Open in Maps
            </a>
          </div>
        </div>

        {/* ── RIGHT: Map ── */}
        <div className="map-container">
          <iframe
            title="Sandriyana Estate Location"
            src={MAP_SRC}
            width="100%"
            height="420"
            allowFullScreen=""
            loading="lazy"
            referrerPolicy="no-referrer-when-downgrade"
          />
        </div>

      </div>
    </section>
  );
}
